import requests
from requests.adapters import HTTPAdapter
from requests.packages.urllib3.util.retry import Retry

def create_retry_session(retries=3, backoff_factor=0.3, status_forcelist=(500, 502, 504)):
    session = requests.Session()
    retries = Retry(total=retries, backoff_factor=backoff_factor, status_forcelist=status_forcelist)
    session.mount('http://', HTTPAdapter(max_retries=retries))
    session.mount('https://', HTTPAdapter(max_retries=retries))
    return session

def fetch_with_retries(url, max_retries=3):
    session = create_retry_session(retries=max_retries)
    for attempt in range(max_retries + 1):
        try:
            response = session.get(url)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            if attempt == max_retries:
                raise Exception(f"Failed to fetch data after {max_retries} attempts") from e
    return None

# Example usage
if __name__ == "__main__":
    url = "https://api.example.com/weather"
    try:
        data = fetch_with_retries(url)
        print(data)
    except Exception as e:
        print(f"Error: {e}")
