# Mocking a database for job tracking
class JobTracker:
    def __init__(self):
        self.jobs = {}
        self.statuses = {}

    def create_job(self, job_id, func, kwargs):
        self.jobs[job_id] = {'func': func, 'kwargs': kwargs, 'status': 'pending'}
        self.statuses[job_id] = 'pending'
        return job_id

    def set_status(self, job_id, status):
        self.statuses[job_id] = status

    def get_status(self, job_id):
        return self.statuses.get(job_id, 'pending')

    def mark_as_completed(self, job_id):
        self.statuses[job_id] = 'completed'

    def mark_as_failed(self, job_id):
        self.statuses[job_id] = 'failed'

tracker = JobTracker()

# Celery broker and backend for in-memory cache
app = Celery('task_queue', backend='memory://', broker='memory://')

@app.task(bind=True, max_retries=3, default_retry_delay=5)
def process_job(self, job_id, **kwargs):
    job = tracker.get_job(job_id)
    try:
        # Process the job
        result = job['func'](**job['kwargs'])
        tracker.mark_as_completed(job_id)
        return result
    except Exception as e:
        tracker.set_status(job_id, 'failed')
        raise self.retry(exc=e)

