import requests
import logging

# Configure basic logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Custom session with retry strategy
class RetryingSession(requests.Session):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.retry_strategy = requests.adapters.Retry(total=3, backoff_factor=0.3, status_forcelist=[500, 502, 504])

    def get(self, url, **kwargs):
        return self.session.get(url, timeout=10, **kwargs)

    def post(self, url, **kwargs):
        return self.session.post(url, timeout=10, **kwargs)

    def put(self, url, **kwargs):
        return self.session.put(url, timeout=10, **kwargs)

    def delete(self, url, **kwargs):
        return self.session.delete(url, timeout=10, **kwargs)

    def _handle_connection_error(self, *args, **kwargs):
        logging.error(f"Connection error: {self.last_response.status_code}")
        return self.retry_strategy

    def _handle_timeout(self, *args, **kwargs):
        logging.error(f"Timeout occurred for: {url}")
        return self.retry_strategy

# Override default exception handling
RetryingSession.last_response = None
RetryingSession.__getattr__ = RetryingSession.get  # Only get, post, put, delete available

# Example usage
if __name__ == "__main__":
    api_url = "https://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q=London"
    retrying_session = RetryingSession()

    try:
        response = retrying_session.get(api_url)
        if response.status_code == 200:
            data = response.json()
            logging.info(f"Data fetched successfully: {data['location']['name']}")
        else:
            logging.warning(f"Non-200 response received: {response.status_code}")
    except requests.RequestException as e:
        logging.error(f"Request failed: {str(e)}")
