from jinja2 import Template
import pandas as pd

class ReportGenerator:
    def __init__(self, base_template):
        self.base_template = base_template

    def _render_table(self, data, headers, style_class):
        return Template(
            '{{% for row in rows %}}<tr {{% if style_class %}}class="{{ style_class }}"{% endif %}}>{{% endfor %}}'
        ).render(rows=[{'col1': row[0], 'col2': row[1], 'style': style_class} for row in data.values()])

    def generate_report(self, data, report_type='default', threshold=0.8):
        template = self.base_template
        # Highlight rows where value > threshold
        highlight_style = 'highlight'
        if data is not None:
            data['status'] = [1 if value > threshold else 0 for value in data['value']]
        return template.render(data=data, report_type=report_type, highlight_style=highlight_style)
